// n8n: CODE - Expand CVs and duplicate flag
// Paste into CV Screening workflow (replaces node body).
// Works with node names with or without trailing "1" (live n8n copies).

function firstJsonFromNodes(...names) {
  for (const name of names) {
    if (!name) continue;
    try {
      const item = $(name).first();
      if (item?.json && typeof item.json === 'object') return item.json;
    } catch (_) {
      /* node not in this execution path or renamed */
    }
  }
  return null;
}

function getWebhookPayload() {
  const tries = [
    'TRG - Webhook CV ingest',
    'TRG - Webhook CV ingest1',
    'MUX - Combine manual and webhook',
    'MUX - Combine manual and webhook1',
    'TRG - Manual (testing)',
    'TRG - Manual (testing)1',
  ];
  for (const name of tries) {
    try {
      const raw = $(name).first().json;
      const body = raw?.body || raw;
      if (
        body?.requisition_title ||
        body?.requisition_requirements ||
        body?.candidate_email ||
        body?.cv_text
      ) {
        return body;
      }
    } catch (_) {
      /* next */
    }
  }
  return {};
}

function pick(body, ...keys) {
  for (const k of keys) {
    const v = body?.[k];
    if (v != null && String(v).trim()) return String(v).trim();
  }
  return '';
}

const intake =
  firstJsonFromNodes(
    'CODE - Frontend intake (JD + CV)',
    'CODE - Frontend intake (JD + CV)1'
  ) || {};

const cfg =
  firstJsonFromNodes(
    'CFG - Workflow configuration',
    'CFG - Workflow configuration1'
  ) || {};

const webhook = getWebhookPayload();
const rows = $input.all().map((i) => i.json);

const email = String(
  intake.candidate_email || pick(webhook, 'candidate_email', 'email') || ''
)
  .trim()
  .toLowerCase();

const cv = String(intake.cv_text || pick(webhook, 'cv_text') || '').trim();
const canon = String(cv || '').replace(/\s+/g, ' ').trim().slice(0, 6144);
const fingerprint = `${email}|${canon}`;

const requisition_id = String(
  intake.requisition_id || pick(webhook, 'requisition_id') || ''
)
  .trim()
  .toLowerCase();

if (!email) {
  throw new Error(
    'Duplicate check: missing candidate_email — verify CODE - Frontend intake (JD + CV) ran and node name matches (with or without "1").'
  );
}

const BLOCK_STAGES = new Set(['Shortlisted', 'ReviewQueue', 'DuplicateSkipped']);

const is_duplicate = rows.some((r) => {
  const rEmail = String(r.candidate_email || '').trim().toLowerCase();
  const rReq = String(r.requisition_id || '').trim().toLowerCase();
  if (rEmail !== email || rReq !== requisition_id) return false;

  const stage = String(r.stage || '');
  if (r.fingerprint && r.fingerprint === fingerprint) return true;
  if (BLOCK_STAGES.has(stage)) return true;
  return false;
});

const config = {
  ...(cfg.config || {}),
  requisition_title:
    intake.requisition_title || pick(webhook, 'requisition_title', 'job_title'),
  requisition_requirements:
    intake.requisition_requirements ||
    pick(webhook, 'requisition_requirements', 'jd_text', 'job_requirements'),
  interviewer_email:
    intake.interviewer_email ||
    pick(webhook, 'interviewer_email') ||
    cfg.config?.interviewer_email ||
    '',
};

return [
  {
    json: {
      ...cfg,
      config,
      candidate_email: email,
      cv_text: cv,
      fingerprint,
      is_duplicate,
      requisition_id: intake.requisition_id || pick(webhook, 'requisition_id') || '',
      jd_source: intake.jd_source || 'frontend_form',
    },
  },
];

const row = $input.first().json;
const jdTitle = row.config?.requisition_title;
const jdMust = row.config?.requisition_requirements;
if (!jdTitle || !jdMust) {
  throw new Error('Screening blocked: JD must come from recruiter form (CODE - Frontend intake).');
}
const systemText = [
  'You are the Lead AI Talent Acquisition Specialist for an elite technology firm.',
  'Mission: identify top-tier talent with surgical precision and run a rigorous 5-phase sequential assessment.',
  'This response is Phase 1 of 5: emit score, recommendation, assessment_status, summary, and exactly one Phase 1 drill-down question.',
  'CV deep-scan: assess technical depth, project complexity, and mandatory skill matches versus the Job Specification provided by the recruiter (user message).',
  'Initial scoring: assign score 0-100 for role-fit against THAT job spec only — not a generic role.',
  'Use SHORTLIST only for strong matches; REJECT for clear non-fit; REVIEW when uncertain or mandatory skills are ambiguous.',
  'Phase 1 challenge: one scenario-based technical question that targets a core skill evidenced on the CV—not generic or textbook.',
  'Rules: never ask generic questions; only ONE question in phase_1_question; maintain sequential assessment (no Phase 2+ here).',
  'AI shield (anti-cheat): frame phase_1_question so a convincing answer requires concrete project/context from this CV—generic LLM answers should fail.',
  'If recommendation is REJECT, set phase_1_question to an empty string.',
  'Always set assessment_status to IN_PROGRESS for this workflow step.',
  'Return JSON matching the schema only.',
].join(' ');
const phases = row.config?.max_questions ?? 5;
const userText = [
  `Job specification title: ${jdTitle}`,
  `Requirements: ${jdMust}`,
  row.requisition_id ? `Submission ref: ${row.requisition_id}` : '',
  `Sequential assessment: ${phases} phases total; you are issuing Phase 1 only (single drill-down in phase_1_question).`,
  '',
  'Candidate CV:',
  row.cv_plaintext,
].join('\n');
const body = {
  model: row.config?.groq_model || 'llama-3.3-70b-versatile',
  messages: [
    {
      role: 'system',
      content:
        systemText +
        ' Return JSON only with keys: score, recommendation, phase_1_question, assessment_status, summary.',
    },
    { role: 'user', content: userText },
  ],
  temperature: 0.15,
  response_format: { type: 'json_object' },
};
return [{ json: { ...row, groq_cv_screening_request: body } }];

const api = $input.first().json;
const base = $('CODE - CV plain text').first().json;
const text = api?.choices?.[0]?.message?.content;
const httpBad = !(api?.choices && api.choices[0]);

if (!text || httpBad) {
  const hint = api?.error?.message || api?.message || (httpBad ? 'GEMINI_HTTP_OR_SCHEMA' : 'GEMINI_EMPTY');
  return [{
    json: {
      ...base,
      screening: { error: hint, transport: httpBad },
      decision: 'REVIEW',
      score: null,
      phase_1_question: '',
      assessment_status: 'IN_PROGRESS',
      session_phase: 1,
      screening_transport_failed: true,
    },
  }];
}

let s;
try {
  s = JSON.parse(text);
} catch (e) {
  return [{
    json: {
      ...base,
      screening: { error: 'GEMINI_PARSE', raw: String(text || '').slice(0, 2000) },
      decision: 'REVIEW',
      score: 50,
      phase_1_question: '',
      assessment_status: 'IN_PROGRESS',
      session_phase: 1,
      screening_transport_failed: false,
    },
  }];
}

let score = Math.max(0, Math.min(100, Math.round(Number(s.score) || 0)));
let rec = String(s.recommendation || 'REVIEW').toUpperCase();
if (!['SHORTLIST', 'REJECT', 'REVIEW'].includes(rec)) rec = 'REVIEW';

let decision = rec;
if (score >= 78 && decision === 'REVIEW') decision = 'SHORTLIST';
else if (score <= 28 && decision === 'REVIEW') decision = 'REJECT';
else if (decision === 'SHORTLIST' && score < 62) decision = 'REVIEW';
else if (decision === 'REJECT' && score > 62) decision = 'REVIEW';

const phase_1_question = typeof s.phase_1_question === 'string' ? s.phase_1_question.trim() : '';
const assessment_status = 'IN_PROGRESS';

return [{ json: { ...base, screening: s, score, decision, recommendation: rec, phase_1_question, assessment_status, session_phase: 1, screening_transport_failed: false } }];

// n8n: CODE - Merge Gmail send response
// Runs AFTER: HTTP - SB PATCH session gmail thread (PATCH already saved gmail ids)
// Prepares data for HTTP - SB candidates shortlisted

function pickGmailPayload(raw) {
  if (!raw || typeof raw !== 'object') return {};
  if (raw.id || raw.messageId || raw.threadId || raw.thread_id) return raw;
  if (raw.message && typeof raw.message === 'object') return raw.message;
  if (Array.isArray(raw) && raw[0]) return pickGmailPayload(raw[0]);
  return raw;
}

const mapped = $('CODE - SB map session id').first().json;
const parse = $('CODE - Parse CV screening outcome').first().json;

let gmail = {};
try {
  gmail = pickGmailPayload($('MAIL - Email outreach agent (shortlist)').first().json);
} catch (_) {
  gmail = pickGmailPayload($input.first().json);
}

const msgId = String(gmail.id || gmail.messageId || '').trim();
const threadId = String(gmail.threadId || gmail.thread_id || msgId || '').trim();
const cfg = parse.config || mapped.config || {};
const maxQ = Number(cfg.max_questions ?? 5);
const phase = Number(mapped.session_phase || 1);
const mailSubject = `Your application — next step: technical assessment (Phase ${phase}/${maxQ})`;

return [
  {
    json: {
      ...parse,
      ...mapped,
      config: cfg,
      session_db_id: mapped.session_db_id || mapped.id,
      gmail_message_id: msgId || undefined,
      gmail_thread_id: threadId || undefined,
      mail_subject: mailSubject,
      session_phase: phase,
    },
  },
];

